query:
SELECT COUNT(*) as total_conhecimentos_duplicados FROM (
  SELECT titulo, processoOrigemId, COUNT(*) as qtd
  FROM conhecimentos 
  GROUP BY titulo, processoOrigemId 
  HAVING COUNT(*) > 1
) t;

